type Status = "idle" | "loading" | "error";

async function api<T>(path: string): Promise<T> {
  const res = await fetch(path);
  if (!res.ok) throw new Error(res.statusText);
  return res.json() as Promise<T>;
}

type User = { id: string };
const user = await api<User>("/user");
